import{_ as r,o as t,c as d,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"功德木鱼","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/功德木鱼.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/功德木鱼.md"}'),o={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/功德木鱼.md"};function l(p,a,_,i,b,c){return t(),d("div",null,[...a[0]||(a[0]=[e("h1",{id:"功德木鱼",tabindex:"-1"},[n("功德木鱼 "),e("a",{class:"header-anchor",href:"#功德木鱼","aria-label":'Permalink to "功德木鱼"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风029特别节愚人版")])])],-1),s('<h1 id="功德木鱼-1" tabindex="-1">功德木鱼 <a class="header-anchor" href="#功德木鱼-1" aria-label="Permalink to &quot;功德木鱼&quot;">​</a></h1><p>功德木鱼<br> D+500<br> 奇物<br> 一个个看起来普普通通的木制木鱼，配着一把木头小锤，用小锤敲击木头的时候会发出嘟嘟嘟的声音，并会在角色头上显示功德+1的字样。<br> 你可以通过木鱼来获得功德，每次敲击功德加1，但你因此获得的功德最多只能存储100点，如果你把木鱼转让给其他人，你的功德也会同步转移给他们。你可以消耗功德来获得以下的效果，持续一场景。<br> 消耗20功德:你攻击【黑暗生物】时获得1dp士气加值。<br> 消耗40功德:你攻击【黑暗生物】时获得1dp士气加值和1点抵破魔。<br> 消耗60功德:你攻击【黑暗生物】时获得1dp士气加值和1点抵破魔并在【黑暗生物】攻击你时获得1点力场防御。<br> 消耗100功德:你攻击【黑暗生物】时获得1dp士气加值和1点抵破魔并在【黑暗生物】攻击你时获得1点力场防御，若你因为【黑暗生物】的攻击满足了开启基因锁的条件，那么这次基因锁的开启获得1点机运加值。<br> 特别的是，在战斗中你也可以通过消耗一个移动动作来快速敲击木鱼来快速积攒功德。这会让你在一轮内获得至多60功德,如果一轮获得的功德超过了这个量会被佛祖认为恶意刷功德导致功德清零。<br> 获得功德的过程是不可以被孤魂野鬼肆意打断的，因此在获得功德的过程中你被视为拥有仅对于【黑暗生物】生效的攻击劣化一级，这是基于力场防御的效果，持续一轮。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(o,[["render",l]]);export{f as __pageData,m as default};
